import{_ as e,o as n,c as t,ag as r}from"./chunks/framework.Culc7SYV.js";const u=JSON.parse('{"title":"Syncing","description":"","frontmatter":{},"headers":[],"relativePath":"Syncing.md","filePath":"Syncing.md","lastUpdated":1772690052000}'),s={name:"Syncing.md"};function i(o,a,l,c,d,h){return n(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="syncing" tabindex="-1">Syncing <a class="header-anchor" href="#syncing" aria-label="Permalink to &quot;Syncing&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Syncing updates LearnKit&#39;s card database from your Markdown notes.</p><p>After creating, editing, or deleting card blocks, sync so changes take effect in your card database.</p><h2 id="start-sync" tabindex="-1">Start Sync <a class="header-anchor" href="#start-sync" aria-label="Permalink to &quot;Start Sync&quot;">​</a></h2><ul><li><strong>Header button:</strong> click the LearnKit sync button in any view when LearnKit is open.</li><li><strong>Manual command:</strong> run <strong>LearnKit: Sync cards</strong> from the command palette.</li><li><strong>Automatic sync:</strong> runs when editing cards in <a href="./Card-Browser">Card Browser</a> or edit modals.</li></ul><h2 id="sync-steps" tabindex="-1">Sync Steps <a class="header-anchor" href="#sync-steps" aria-label="Permalink to &quot;Sync Steps&quot;">​</a></h2><ol><li><strong>Scan:</strong> find card blocks in Markdown files.</li><li><strong>Parse:</strong> read fields using the configured delimiter (default <code>|</code>).</li><li><strong>Match:</strong> connect blocks with existing <code>^learnkit-#########</code> anchors to stored scheduling data.</li><li><strong>Create:</strong> add new blocks that do not yet have anchors.</li><li><strong>Update:</strong> refresh stored data for changed blocks.</li><li><strong>Remove:</strong> delete cards whose source blocks were removed.</li><li><strong>Anchor:</strong> insert <code>^learnkit-#########</code> above or below blocks (based on settings).</li></ol><h2 id="card-anchors" tabindex="-1">Card Anchors <a class="header-anchor" href="#card-anchors" aria-label="Permalink to &quot;Card Anchors&quot;">​</a></h2><p>After syncing, each card block gets an anchor line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>^learnkit-#########</span></span></code></pre></div><p>This anchor links note content to scheduling data.</p><p>Do not edit or delete it. If it is removed, next sync creates a new ID and previous progress is not linked to that block.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If you remove an anchor by mistake, find the card ID in <a href="./Card-Browser">Card Browser</a> and re-add the line.</p></div><h2 id="quarantine" tabindex="-1">Quarantine <a class="header-anchor" href="#quarantine" aria-label="Permalink to &quot;Quarantine&quot;">​</a></h2><p>If a card block has invalid syntax, LearnKit quarantines it instead of deleting it.</p><p>See quarantined entries in Settings with error details, fix the note, then sync again.</p><h2 id="exclusions" tabindex="-1">Exclusions <a class="header-anchor" href="#exclusions" aria-label="Permalink to &quot;Exclusions&quot;">​</a></h2><ul><li><strong>Fenced code blocks:</strong> ignored by default (can be changed in Settings → Indexing).</li><li><strong>Non-Markdown files:</strong> not scanned.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Cards">Cards</a></li><li><a href="./Creating-Cards">Creating Cards</a></li><li><a href="./Backups">Backups</a></li></ul>',22)])])}const p=e(s,[["render",i]]);export{u as __pageData,p as default};
